// Count Blood Bags
const inventory = $input.all();

const counts = {};

for (const item of inventory) {

    const hospital = item.json.Hospital_ID;

    if (!counts[hospital]) {
        counts[hospital] = 0;
    }

    counts[hospital]++;
}

return Object.entries(counts).map(([hospital, total]) => ({
    json: {
        Hospital_ID: hospital,
        Available_Bags: total
    }
}));

