parameters.jsCode:
// Get all incoming items
const items = $input.all();

// The last item is the requesting hospital
const requestedHospital = items[items.length - 1].json;

// All previous items are candidate hospitals
const candidateHospitals = items
  .slice(0, items.length - 1)
  .map(item => item.json);

return [
  {
    json: {
      requested_hospital: requestedHospital,
      candidate_hospitals: candidateHospitals
    }
  }
];

